SELECT issueid__c FROM "Case" WHERE orderitemid__c IN (
  SELECT id FROM "OrderItem" WHERE product2id = '01tWt000006hV8LIAU'
) AND createddate >= '2022-08-16' AND createddate < '2023-01-17' AND issueid__c IS NOT NULL;

SELECT Id, OwnerId, CreatedDate, ContractID__c FROM Opportunity WHERE ContractID__c IS NOT NULL AND (
  COALESCE(TRY_STRPTIME(CreatedDate, '%Y-%m-%dT%H:%M:%S.%f%z'), TRY_STRPTIME(CreatedDate, '%Y-%m-%dT%H:%M:%S.%f'), TRY_STRPTIME(CreatedDate, '%Y-%m-%dT%H:%M:%S'), TRY_STRPTIME(CreatedDate, '%Y-%m-%d %H:%M:%S'), TRY_STRPTIME(CreatedDate, '%Y-%m-%d'), TRY_STRPTIME(CreatedDate, '%m/%d/%Y'), TRY_STRPTIME(CreatedDate, '%Y/%m/%d')) BETWEEN DATE '2023-04-01' AND DATE '2023-04-30'
);
